// JanaShakti AI proxy — keeps the Gemini key server-side; returns { text }.
const body = $input.first().json.body || $input.first().json;
const parts = body.parts || [];

const GEMINI_KEY = $env.JANASHAKTI_GEMINI_KEY;

let text = '';

// Gemini chain — fall through on failure.
const models = ['gemini-2.5-flash', 'gemini-2.5-flash-lite', 'gemini-2.0-flash'];
for (const model of models) {
  try {
    const resp = await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://generativelanguage.googleapis.com/v1beta/models/' + model + ':generateContent?key=' + GEMINI_KEY,
      headers: { 'Content-Type': 'application/json' },
      body: { contents: [{ parts }], generationConfig: { temperature: 0.1 } },
      json: true,
    });
    const t = resp.candidates && resp.candidates[0] && resp.candidates[0].content && resp.candidates[0].content.parts[0] && resp.candidates[0].content.parts[0].text;
    if (t) { text = t; break; }
  } catch (e) { /* try next model */ }
}

return [{ json: { text } }];
